using UnityEngine;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建造模式控制器，管理建造流程：选择建筑→预览放置→确认/取消。
    /// 波西亚时光风格：鼠标跟随+网格吸附+90°旋转。
    /// </summary>
    public class BuildModeController : MonoBehaviour
    {
        public enum BuildState
        {
            Idle,
            Placing
        }

        [Header("引用")]
        [SerializeField] private GridManager _gridManager;
        [SerializeField] private BuildingManager _buildingManager;

        [Header("配置")]
        [SerializeField] private LayerMask _groundLayer;
        [SerializeField] private float _ghostYOffset = 0f;

        private BuildState _state = BuildState.Idle;
        private BuildingData _currentBuilding;
        private GhostPreview _ghost;
        private int _currentRotation = 0;
        private Vector2Int _currentGridPos;
        private Plane _groundPlane;

        public BuildState State => _state;
        public bool IsPlacing => _state == BuildState.Placing;

        public event System.Action<BuildState> OnStateChanged;

        private void Awake()
        {
            _groundPlane = new Plane(Vector3.up, Vector3.zero);
        }

        private void Update()
        {
            if (_state != BuildState.Placing || _ghost == null) return;

            UpdateGhostPosition();
            HandleInput();
        }

        #region 进入/退出建造模式

        /// <summary>
        /// 进入建造模式，开始放置指定建筑。
        /// </summary>
        public void EnterBuildMode(BuildingData data)
        {
            if (data == null) return;

            // 如果已在放置中，先清理
            if (_state == BuildState.Placing)
                CancelBuildMode();

            _currentBuilding = data;
            _currentRotation = 0;
            _state = BuildState.Placing;

            CreateGhost(data);
            OnStateChanged?.Invoke(_state);

            Debug.Log($"[BuildMode] 进入建造模式: {data.buildingName}");
        }

        /// <summary>
        /// 取消建造模式。
        /// </summary>
        public void CancelBuildMode()
        {
            if (_ghost != null)
            {
                _ghost.Cleanup();
                Destroy(_ghost.gameObject);
                _ghost = null;
            }

            _currentBuilding = null;
            _state = BuildState.Idle;
            OnStateChanged?.Invoke(_state);

            Debug.Log("[BuildMode] 退出建造模式");
        }

        #endregion

        #region 幽灵预览

        private void CreateGhost(BuildingData data)
        {
            GameObject ghostObj;

            if (data.prefab != null)
            {
                ghostObj = Instantiate(data.prefab);
            }
            else
            {
                // 无 prefab 时用彩色方块占位
                ghostObj = GameObject.CreatePrimitive(PrimitiveType.Cube);
                ghostObj.transform.localScale = new Vector3(
                    data.gridSize.x, 0.5f, data.gridSize.y
                );
                var renderer = ghostObj.GetComponent<Renderer>();
                renderer.sharedMaterial = new Material(Shader.Find("Universal Render Pipeline/Lit"));
                renderer.sharedMaterial.color = GetPlaceholderColor(data.buildingType);
            }

            ghostObj.name = $"Ghost_{data.buildingName}";
            _ghost = ghostObj.AddComponent<GhostPreview>();
            _ghost.Initialize(data);
        }

        private void UpdateGhostPosition()
        {
            // 射线检测鼠标在地面的位置
            Ray ray = Camera.main.ScreenPointToRay(Input.mousePosition);
            if (_groundPlane.Raycast(ray, out float distance))
            {
                Vector3 hitPoint = ray.GetPoint(distance);
                _currentGridPos = _gridManager.WorldToGrid(hitPoint);

                // 计算考虑旋转后的网格尺寸
                Vector2Int effectiveSize = GetEffectiveSize();
                Vector2Int adjustedStart = _currentGridPos;

                // 吸附到网格
                Vector3 snappedPos = _gridManager.GridToWorld(adjustedStart);
                snappedPos.y = _ghostYOffset;
                _ghost.UpdatePosition(snappedPos, adjustedStart, _currentRotation);

                // 检查可放置性
                bool canPlace = _gridManager.IsAreaAvailable(adjustedStart, effectiveSize)
                    && HasEnoughResources();
                _ghost.SetValid(canPlace);
            }
        }

        private void HandleInput()
        {
            // 左键确认放置
            if (Input.GetMouseButtonDown(0))
            {
                ConfirmPlacement();
            }
            // 右键或 Esc 取消
            else if (Input.GetMouseButtonDown(1) || Input.GetKeyDown(KeyCode.Escape))
            {
                CancelBuildMode();
            }
            // R 键旋转
            else if (Input.GetKeyDown(KeyCode.R))
            {
                _currentRotation = (_currentRotation + 90) % 360;
                Debug.Log($"[BuildMode] 旋转: {_currentRotation}°");
            }
        }

        #endregion

        #region 放置确认

        private void ConfirmPlacement()
        {
            if (_currentBuilding == null || _ghost == null) return;

            Vector2Int effectiveSize = GetEffectiveSize();
            Vector2Int start = _currentGridPos;

            // 验证
            if (!_gridManager.IsAreaAvailable(start, effectiveSize))
            {
                Debug.LogWarning("[BuildMode] 此位置不可放置");
                return;
            }

            if (!HasEnoughResources())
            {
                Debug.LogWarning("[BuildMode] 资源不足");
                return;
            }

            // 放置建筑
            Vector3 worldPos = _gridManager.GridToWorld(start);
            var building = _buildingManager.PlaceBuilding(_currentBuilding, worldPos);

            if (building != null)
            {
                // 设置旋转
                building.transform.rotation = Quaternion.Euler(0f, _currentRotation, 0f);

                // 占用网格
                _gridManager.OccupyArea(start, effectiveSize, building);

                // 更新建筑的网格信息
                building.SetGridInfo(start, _currentRotation);

                Debug.Log($"[BuildMode] 建筑已放置: {_currentBuilding.buildingName} at grid {start}");
            }

            // 清理幽灵，继续放置同类建筑
            if (_ghost != null)
            {
                _ghost.Cleanup();
                Destroy(_ghost.gameObject);
                _ghost = null;
            }
            CreateGhost(_currentBuilding);
        }

        #endregion

        #region 辅助

        /// <summary>
        /// 获取考虑旋转后的有效网格尺寸。
        /// 旋转 90°/270° 时宽高互换。
        /// </summary>
        public Vector2Int GetEffectiveSize()
        {
            if (_currentBuilding == null) return Vector2Int.one;

            if (_currentRotation == 90 || _currentRotation == 270)
            {
                return new Vector2Int(_currentBuilding.gridSize.y, _currentBuilding.gridSize.x);
            }
            return _currentBuilding.gridSize;
        }

        private bool HasEnoughResources()
        {
            if (_currentBuilding == null) return false;
            var levelData = _currentBuilding.GetLevelData(1);
            var profile = PlayerProfile.Instance;
            return profile != null && profile.HasEnoughGold(levelData.buildCost);
        }

        private Color GetPlaceholderColor(BuildingType type)
        {
            switch (type)
            {
                case BuildingType.ResourceGen: return new Color(0.2f, 0.8f, 0.3f, 0.6f);
                case BuildingType.Portal: return new Color(0.3f, 0.5f, 1f, 0.6f);
                case BuildingType.Storage: return new Color(0.9f, 0.7f, 0.2f, 0.6f);
                case BuildingType.Decoration: return new Color(0.9f, 0.4f, 0.7f, 0.6f);
                case BuildingType.Special: return new Color(1f, 0.5f, 0.1f, 0.6f);
                default: return new Color(1f, 1f, 1f, 0.6f);
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建造菜单 UI，显示可建造的建筑列表。
    /// 点击建筑按钮后进入建造模式（由 BuildModeController 管理）。
    /// </summary>
    public class BuildMenuUI : MonoBehaviour
    {
        [Header("UI 引用")]
        [SerializeField] private Transform _buttonContainer;
        [SerializeField] private GameObject _buildButtonPrefab;
        [SerializeField] private Button _closeButton;

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private BuildModeController _buildModeController;

        private void Awake()
        {
            if (_closeButton != null)
                _closeButton.onClick.AddListener(Close);
        }

        private void OnDestroy()
        {
            if (_closeButton != null)
                _closeButton.onClick.RemoveListener(Close);
        }

        private void OnEnable()
        {
            GenerateButtons();
        }

        /// <summary>
        /// 根据可用建筑列表动态生成按钮。
        /// </summary>
        private void GenerateButtons()
        {
            if (_buttonContainer == null || _buildingManager == null) return;

            // 清除旧按钮
            foreach (Transform child in _buttonContainer)
            {
                Destroy(child.gameObject);
            }

            var buildings = _buildingManager.AvailableBuildings;
            if (buildings == null) return;

            var profile = PlayerProfile.Instance;

            foreach (var data in buildings)
            {
                if (data == null) continue;

                GameObject buttonObj;
                if (_buildButtonPrefab != null)
                {
                    buttonObj = Instantiate(_buildButtonPrefab, _buttonContainer);
                }
                else
                {
                    buttonObj = CreateDefaultButton(data);
                }

                SetupButton(buttonObj, data, profile);
            }
        }

        private GameObject CreateDefaultButton(BuildingData data)
        {
            var go = new GameObject($"Btn_{data.buildingName}");
            go.transform.SetParent(_buttonContainer, false);

            var rect = go.AddComponent<RectTransform>();
            rect.sizeDelta = new Vector2(160f, 60f);

            var image = go.AddComponent<Image>();
            image.color = new Color(0.2f, 0.2f, 0.2f, 0.9f);

            var button = go.AddComponent<Button>();

            // 名称文本
            var textObj = new GameObject("Text");
            textObj.transform.SetParent(go.transform, false);
            var textRect = textObj.AddComponent<RectTransform>();
            textRect.anchorMin = Vector2.zero;
            textRect.anchorMax = Vector2.one;
            textRect.offsetMin = Vector2.zero;
            textRect.offsetMax = Vector2.zero;
            var text = textObj.AddComponent<Text>();
            text.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            text.fontSize = 14;
            text.alignment = TextAnchor.MiddleCenter;
            text.color = Color.white;
            var levelData = data.GetLevelData(1);
            text.text = $"{data.buildingName}\n{levelData.buildCost}G";

            return go;
        }

        private void SetupButton(GameObject buttonObj, BuildingData data, PlayerProfile profile)
        {
            var button = buttonObj.GetComponent<Button>();
            if (button == null) return;

            var levelData = data.GetLevelData(1);
            bool canAfford = profile != null && profile.HasEnoughGold(levelData.buildCost);

            // 负担不起时变灰
            if (!canAfford)
            {
                var colors = button.colors;
                colors.normalColor = new Color(0.5f, 0.5f, 0.5f, 1f);
                colors.highlightedColor = new Color(0.6f, 0.6f, 0.6f, 1f);
                button.colors = colors;
            }

            button.onClick.AddListener(() =>
            {
                if (_buildModeController != null)
                {
                    _buildModeController.EnterBuildMode(data);
                    Close();
                }
            });
        }

        public void Open()
        {
            gameObject.SetActive(true);
            GenerateButtons();
        }

        public void Close()
        {
            gameObject.SetActive(false);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主界面 UI，显示资源栏、建筑菜单和操作按钮。
    /// </summary>
    public class HomeMainUI : MonoBehaviour
    {
        [Header("资源栏")]
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _diamondText;
        [SerializeField] private Text _woodText;
        [SerializeField] private Text _stoneText;
        [SerializeField] private Text _foodText;
        [SerializeField] private Text _levelText;

        [Header("按钮")]
        [SerializeField] private Button _collectAllButton;
        [SerializeField] private Button _buildMenuButton;

        [Header("建筑菜单")]
        [SerializeField] private GameObject _buildMenuPanel;
        [SerializeField] private Transform _buildButtonContainer;
        [SerializeField] private BuildMenuUI _buildMenuUI;

        [Header("建造模式提示")]
        [SerializeField] private GameObject _buildModeHint;
        [SerializeField] private BuildModeController _buildModeController;

        [Header("组件引用")]
        [SerializeField] private HomeManager _homeManager;
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;

        private void Start()
        {
            SetupButtons();
            SubscribeEvents();
            RefreshUI();

            // 建造模式提示默认隐藏
            if (_buildModeHint != null)
                _buildModeHint.SetActive(false);

            // 监听建造模式状态变化
            if (_buildModeController != null)
                _buildModeController.OnStateChanged += OnBuildStateChanged;
        }

        private void OnDestroy()
        {
            UnsubscribeEvents();

            if (_buildModeController != null)
                _buildModeController.OnStateChanged -= OnBuildStateChanged;
        }

        private void SetupButtons()
        {
            if (_collectAllButton != null)
                _collectAllButton.onClick.AddListener(OnCollectAllClicked);

            if (_buildMenuButton != null)
                _buildMenuButton.onClick.AddListener(ToggleBuildMenu);

            if (_buildMenuPanel != null)
                _buildMenuPanel.SetActive(false);
        }

        #region 事件订阅

        private void SubscribeEvents()
        {
            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                profile.OnGoldChanged += OnGoldChanged;
                profile.OnDiamondChanged += OnDiamondChanged;
                profile.OnLevelChanged += OnLevelChanged;
            }

            if (_resourceManager != null)
            {
                _resourceManager.OnLocalResourcesChanged += OnLocalResourcesChanged;
            }
        }

        private void UnsubscribeEvents()
        {
            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                profile.OnGoldChanged -= OnGoldChanged;
                profile.OnDiamondChanged -= OnDiamondChanged;
                profile.OnLevelChanged -= OnLevelChanged;
            }

            if (_resourceManager != null)
            {
                _resourceManager.OnLocalResourcesChanged -= OnLocalResourcesChanged;
            }
        }

        #endregion

        #region UI 更新

        private void RefreshUI()
        {
            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                SetText(_goldText, profile.Gold.ToString());
                SetText(_diamondText, profile.Diamond.ToString());
                SetText(_levelText, $"Lv.{profile.Level}");
            }

            if (_resourceManager != null)
            {
                SetText(_woodText, _resourceManager.Wood.ToString());
                SetText(_stoneText, _resourceManager.Stone.ToString());
                SetText(_foodText, _resourceManager.Food.ToString());
            }
        }

        private void OnGoldChanged(int gold)
        {
            SetText(_goldText, gold.ToString());
        }

        private void OnDiamondChanged(int diamond)
        {
            SetText(_diamondText, diamond.ToString());
        }

        private void OnLevelChanged(int level)
        {
            SetText(_levelText, $"Lv.{level}");
        }

        private void OnLocalResourcesChanged(int wood, int stone, int food)
        {
            SetText(_woodText, wood.ToString());
            SetText(_stoneText, stone.ToString());
            SetText(_foodText, food.ToString());
        }

        private void SetText(Text text, string value)
        {
            if (text != null) text.text = value;
        }

        #endregion

        #region 按钮回调

        private void OnCollectAllClicked()
        {
            _homeManager?.OnCollectAllClicked();
        }

        private void ToggleBuildMenu()
        {
            if (_buildMenuUI != null)
            {
                if (_buildMenuPanel != null)
                {
                    bool show = !_buildMenuPanel.activeSelf;
                    _buildMenuPanel.SetActive(show);
                    if (show) _buildMenuUI.Open();
                    else _buildMenuUI.Close();
                }
            }
            else if (_buildMenuPanel != null)
            {
                _buildMenuPanel.SetActive(!_buildMenuPanel.activeSelf);
            }
        }

        private void OnBuildStateChanged(BuildModeController.BuildState state)
        {
            if (_buildModeHint != null)
                _buildModeHint.SetActive(state == BuildModeController.BuildState.Placing);
        }

        /// <summary>
        /// 返回按钮回调（返回家园或退出）。
        /// </summary>
        public void OnBackClicked()
        {
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null && moduleManager.ActiveModuleId != "home")
            {
                moduleManager.DeactivateCurrentModule();
            }
        }

        #endregion
    }
}

using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑预览幽灵，跟随鼠标在网格上移动，显示可放置状态（绿/红）。
    /// </summary>
    public class GhostPreview : MonoBehaviour
    {
        [Header("材质")]
        [SerializeField] private Material _validMaterial;
        [SerializeField] private Material _invalidMaterial;

        private Renderer[] _renderers;
        private Material[] _originalMaterials;
        private bool _isShowingValid = true;

        public BuildingData Data { get; private set; }
        public Vector2Int GridPosition { get; private set; }
        public int Rotation { get; private set; }

        private void Awake()
        {
            _renderers = GetComponentsInChildren<Renderer>();
        }

        /// <summary>
        /// 用建筑数据初始化幽灵。
        /// </summary>
        public void Initialize(BuildingData data)
        {
            Data = data;

            if (data.prefab != null)
            {
                // 如果有 prefab，用 prefab 的 Renderer
                _renderers = GetComponentsInChildren<Renderer>();
            }

            // 保存原始材质并替换为半透明
            _originalMaterials = new Material[_renderers.Length];
            for (int i = 0; i < _renderers.Length; i++)
            {
                _originalMaterials[i] = _renderers[i].sharedMaterial;
            }

            SetTransparency(0.6f);
            SetValid(true);
        }

        /// <summary>
        /// 更新幽灵位置和旋转。
        /// </summary>
        public void UpdatePosition(Vector3 worldPos, Vector2Int gridPos, int rotation)
        {
            transform.position = worldPos;
            GridPosition = gridPos;
            Rotation = rotation;
            transform.rotation = Quaternion.Euler(0f, rotation, 0f);
        }

        /// <summary>
        /// 设置预览状态：可放置（绿色）或不可放置（红色）。
        /// </summary>
        public void SetValid(bool isValid)
        {
            if (_isShowingValid == isValid) return;
            _isShowingValid = isValid;

            Material mat = isValid ? _validMaterial : _invalidMaterial;
            if (mat != null)
            {
                foreach (var r in _renderers)
                {
                    r.sharedMaterial = mat;
                }
            }
            else
            {
                // 没有自定义材质时，用颜色变化
                foreach (var r in _renderers)
                {
                    if (r.sharedMaterial != null)
                    {
                        var c = r.sharedMaterial.color;
                        r.sharedMaterial.color = isValid
                            ? new Color(0.5f, 1f, 0.5f, 0.6f)
                            : new Color(1f, 0.3f, 0.3f, 0.6f);
                    }
                }
            }
        }

        /// <summary>
        /// 清理幽灵，恢复原始材质。
        /// </summary>
        public void Cleanup()
        {
            for (int i = 0; i < _renderers.Length; i++)
            {
                if (_renderers[i] != null && _originalMaterials != null && i < _originalMaterials.Length)
                {
                    _renderers[i].sharedMaterial = _originalMaterials[i];
                }
            }
        }

        private void SetTransparency(float alpha)
        {
            foreach (var r in _renderers)
            {
                if (r.sharedMaterial != null)
                {
                    var c = r.sharedMaterial.color;
                    r.sharedMaterial.color = new Color(c.r, c.g, c.b, alpha);
                }
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 网格管理器，管理 2.5D 场景中建筑占用的网格。
    /// 建筑在 XZ 平面上摆放，Y 轴为高度。
    /// </summary>
    public class GridManager : MonoBehaviour
    {
        [Header("网格配置")]
        [SerializeField] private float _cellSize = 1f;
        [SerializeField] private int _gridWidth = 20;
        [SerializeField] private int _gridHeight = 20;
        [SerializeField] private Vector3 _origin = Vector3.zero;

        [Header("可视化")]
        [SerializeField] private bool _showGrid = true;
        [SerializeField] private Color _gridColor = new Color(1f, 1f, 1f, 0.15f);
        [SerializeField] private Color _occupiedColor = new Color(1f, 0f, 0f, 0.3f);

        /// <summary>网格坐标 → 占用该格的建筑</summary>
        private Dictionary<Vector2Int, BuildingBase> _occupancy = new Dictionary<Vector2Int, BuildingBase>();

        public float CellSize => _cellSize;
        public int GridWidth => _gridWidth;
        public int GridHeight => _gridHeight;

        #region 坐标转换

        /// <summary>世界坐标 → 网格坐标</summary>
        public Vector2Int WorldToGrid(Vector3 worldPos)
        {
            Vector3 local = worldPos - _origin;
            int x = Mathf.FloorToInt(local.x / _cellSize);
            int y = Mathf.FloorToInt(local.z / _cellSize);
            return new Vector2Int(x, y);
        }

        /// <summary>网格坐标 → 世界坐标（格子中心点）</summary>
        public Vector3 GridToWorld(Vector2Int gridPos)
        {
            return _origin + new Vector3(
                (gridPos.x + 0.5f) * _cellSize,
                0f,
                (gridPos.y + 0.5f) * _cellSize
            );
        }

        /// <summary>世界坐标吸附到网格中心</summary>
        public Vector3 SnapToGrid(Vector3 worldPos)
        {
            return GridToWorld(WorldToGrid(worldPos));
        }

        #endregion

        #region 占用查询

        /// <summary>判断网格坐标是否在有效范围内</summary>
        public bool IsValidGridPos(Vector2Int gridPos)
        {
            return gridPos.x >= 0 && gridPos.x < _gridWidth
                && gridPos.y >= 0 && gridPos.y < _gridHeight;
        }

        /// <summary>判断指定区域是否全部空闲</summary>
        public bool IsAreaAvailable(Vector2Int start, Vector2Int size)
        {
            for (int x = start.x; x < start.x + size.x; x++)
            {
                for (int y = start.y; y < start.y + size.y; y++)
                {
                    var pos = new Vector2Int(x, y);
                    if (!IsValidGridPos(pos)) return false;
                    if (_occupancy.ContainsKey(pos)) return false;
                }
            }
            return true;
        }

        /// <summary>获取占用指定格子的建筑</summary>
        public BuildingBase GetOccupant(Vector2Int gridPos)
        {
            _occupancy.TryGetValue(gridPos, out var building);
            return building;
        }

        #endregion

        #region 占用操作

        /// <summary>占用指定区域</summary>
        public bool OccupyArea(Vector2Int start, Vector2Int size, BuildingBase building)
        {
            if (!IsAreaAvailable(start, size)) return false;

            for (int x = start.x; x < start.x + size.x; x++)
            {
                for (int y = start.y; y < start.y + size.y; y++)
                {
                    _occupancy[new Vector2Int(x, y)] = building;
                }
            }
            return true;
        }

        /// <summary>释放指定区域</summary>
        public void ReleaseArea(Vector2Int start, Vector2Int size)
        {
            for (int x = start.x; x < start.x + size.x; x++)
            {
                for (int y = start.y; y < start.y + size.y; y++)
                {
                    _occupancy.Remove(new Vector2Int(x, y));
                }
            }
        }

        /// <summary>释放指定建筑占用的所有格子</summary>
        public void ReleaseBuilding(BuildingBase building)
        {
            var keysToRemove = new List<Vector2Int>();
            foreach (var kvp in _occupancy)
            {
                if (kvp.Value == building)
                    keysToRemove.Add(kvp.Key);
            }
            foreach (var key in keysToRemove)
                _occupancy.Remove(key);
        }

        /// <summary>清除所有占用</summary>
        public void ClearAll()
        {
            _occupancy.Clear();
        }

        #endregion

        #region Gizmos 可视化

#if UNITY_EDITOR
        private void OnDrawGizmos()
        {
            if (!_showGrid) return;

            // 画网格线
            Gizmos.color = _gridColor;
            for (int x = 0; x <= _gridWidth; x++)
            {
                Vector3 from = _origin + new Vector3(x * _cellSize, 0.01f, 0f);
                Vector3 to = _origin + new Vector3(x * _cellSize, 0.01f, _gridHeight * _cellSize);
                Gizmos.DrawLine(from, to);
            }
            for (int y = 0; y <= _gridHeight; y++)
            {
                Vector3 from = _origin + new Vector3(0f, 0.01f, y * _cellSize);
                Vector3 to = _origin + new Vector3(_gridWidth * _cellSize, 0.01f, y * _cellSize);
                Gizmos.DrawLine(from, to);
            }

            // 画占用格子
            Gizmos.color = _occupiedColor;
            foreach (var kvp in _occupancy)
            {
                Vector3 center = GridToWorld(kvp.Key);
                center.y = 0.02f;
                Gizmos.DrawCube(center, new Vector3(_cellSize * 0.9f, 0.01f, _cellSize * 0.9f));
            }
        }
#endif

        #endregion
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主控制器，管理家园场景的初始化和生命周期。
    /// 作为 GameModule 注册到 ModuleManager。
    /// </summary>
    public class HomeManager : GameModule
    {
        private const string MODULE_ID = "home";
        private const string MODULE_DISPLAY_NAME = "家园";
        private const string SAVE_KEY = "homebase";

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;

        [Header("初始建筑")]
        [SerializeField] private BuildingData[] _starterBuildings;
        [SerializeField] private Vector3[] _starterPositions;

        private bool _isLoaded = false;

        private void Awake()
        {
            _moduleId = MODULE_ID;
            _displayName = MODULE_DISPLAY_NAME;
            _sceneName = gameObject.scene.name;
        }

        private void Start()
        {
            InitializeHome();
        }

        private void InitializeHome()
        {
            if (_isLoaded) return;

            // 注册到 ModuleManager
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null)
            {
                moduleManager.RegisterModule(this);
            }

            // 尝试从存档加载
            LoadHomeSave();

            // 如果没有建筑，放置初始建筑
            if (_buildingManager.Buildings.Count == 0)
            {
                PlaceStarterBuildings();
            }

            _isLoaded = true;
            Debug.Log("[HomeManager] 家园初始化完成");
        }

        private void PlaceStarterBuildings()
        {
            if (_starterBuildings == null || _starterPositions == null) return;

            int count = Mathf.Min(_starterBuildings.Length, _starterPositions.Length);
            for (int i = 0; i < count; i++)
            {
                if (_starterBuildings[i] != null)
                {
                    _buildingManager.PlaceBuilding(_starterBuildings[i], _starterPositions[i]);
                }
            }

            Debug.Log($"[HomeManager] 放置 {count} 个初始建筑");
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var saveData = new HomeSaveData();
            _resourceManager?.SaveToSave(saveData);
            saveData.buildings = _buildingManager?.ExportSaveData();
            return JsonUtility.ToJson(saveData);
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            if (string.IsNullOrEmpty(jsonData)) return;

            try
            {
                var saveData = JsonUtility.FromJson<HomeSaveData>(jsonData);
                _resourceManager?.LoadFromSave(saveData);
                _buildingManager?.RestoreFromSaveData(saveData.buildings);
            }
            catch (Exception e)
            {
                Debug.LogError($"[HomeManager] 恢复存档失败: {e.Message}");
            }
        }

        private void LoadHomeSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = saveSystem.LoadModuleData(SAVE_KEY);
            if (!string.IsNullOrEmpty(json))
            {
                RestoreModuleSaveData(json);
                Debug.Log("[HomeManager] 家园存档已加载");
            }
        }

        private void SaveHomeData()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = GetModuleSaveData();
            saveSystem.SaveModuleData(SAVE_KEY, json, 1);
        }

        #endregion

        #region 模块生命周期

        public override void Activate()
        {
            base.Activate();
            Debug.Log("[HomeManager] 家园已激活");
        }

        public override void Deactivate()
        {
            SaveHomeData();
            base.Deactivate();
            Debug.Log("[HomeManager] 家园已停用");
        }

        #endregion

        #region 按钮回调

        /// <summary>
        /// 收集所有资源按钮回调。
        /// </summary>
        public void OnCollectAllClicked()
        {
            _resourceManager?.CollectAllResources();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveHomeData();
        }

        private void OnApplicationQuit()
        {
            SaveHomeData();
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Shared.Player
{
    /// <summary>
    /// 统一玩家档案，管理跨所有模块共享的玩家数据。
    /// 包含货币（金币、钻石）、等级、经验值。
    /// </summary>
    public class PlayerProfile : Singleton<PlayerProfile>
    {
        [Header("初始值")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _gold;
        private int _diamond;
        private int _stamina;
        private int _level = 1;
        private int _currentExp;

        #region 属性

        public int Gold => _gold;
        public int Diamond => _diamond;
        public int Stamina => _stamina;
        public int Level => _level;
        public int CurrentExp => _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => GetExpRequiredForLevel(_level);
        public float ExpProgress => _level >= _maxLevel ? 1f : (float)_currentExp / ExpToNextLevel;
        public bool IsMaxLevel => _level >= _maxLevel;

        #endregion

        #region 事件

        public event Action<int> OnGoldChanged;
        public event Action<int> OnDiamondChanged;
        public event Action<int> OnStaminaChanged;
        public event Action<int> OnLevelChanged;
        public event Action<int, int> OnExpChanged;

        #endregion

        protected override void Awake()
        {
            base.Awake();
            _gold = _initialGold;
            _diamond = _initialDiamond;
            _stamina = _initialStamina;
        }

        private void Start()
        {
            LoadFromSave();
        }

        #region 金币

        public bool HasEnoughGold(int amount) => _gold >= amount;

        public void AddGold(int amount, string source = "")
        {
            if (amount <= 0) return;
            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = amount,
                DiamondDelta = 0
            });
        }

        public bool SpendGold(int amount, string source = "")
        {
            if (!HasEnoughGold(amount)) return false;
            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = -amount,
                DiamondDelta = 0
            });
            return true;
        }

        #endregion

        #region 钻石

        public bool HasEnoughDiamond(int amount) => _diamond >= amount;

        public void AddDiamond(int amount, string source = "")
        {
            if (amount <= 0) return;
            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = amount
            });
        }

        public bool SpendDiamond(int amount, string source = "")
        {
            if (!HasEnoughDiamond(amount)) return false;
            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = -amount
            });
            return true;
        }

        #endregion

        #region 体力

        public bool HasEnoughStamina(int amount) => _stamina >= amount;

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;
            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
        }

        public bool SpendStamina(int amount)
        {
            if (!HasEnoughStamina(amount)) return false;
            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            return true;
        }

        #endregion

        #region 等级与经验

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            GlobalEventBus.Publish(new PlayerLevelChangedEvent
            {
                OldLevel = oldLevel,
                NewLevel = _level,
                CurrentExp = _currentExp,
                ExpToNext = ExpToNextLevel
            });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                Debug.Log($"[PlayerProfile] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            var data = saveSystem.CurrentSave.player;
            _gold = data.gold > 0 ? data.gold : _initialGold;
            _diamond = data.diamond > 0 ? data.diamond : _initialDiamond;
            _stamina = data.stamina > 0 ? data.stamina : _initialStamina;
            _level = Mathf.Clamp(data.playerLevel, 1, _maxLevel);
            _currentExp = Mathf.Clamp(data.playerExp, 0, ExpToNextLevel);

            Debug.Log($"[PlayerProfile] 从存档加载: Lv.{_level}, Gold={_gold}, Diamond={_diamond}");
        }

        public void PersistToSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            saveSystem.CurrentSave.player.gold = _gold;
            saveSystem.CurrentSave.player.diamond = _diamond;
            saveSystem.CurrentSave.player.stamina = _stamina;
            saveSystem.CurrentSave.player.playerLevel = _level;
            saveSystem.CurrentSave.player.playerExp = _currentExp;
            saveSystem.SaveGame();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }
    }
}

using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 传送门特效控制器，管理光晕脉冲和粒子强度。
    /// </summary>
    [RequireComponent(typeof(Light))]
    public class PortalEffectController : MonoBehaviour
    {
        [Header("脉冲配置")]
        [SerializeField] private float _pulseSpeed = 2f;
        [SerializeField] private float _minIntensity = 1f;
        [SerializeField] private float _maxIntensity = 3f;
        [SerializeField] private float _minRange = 1.5f;
        [SerializeField] private float _maxRange = 2.5f;

        private Light _light;
        private float _timer;

        private void Start()
        {
            _light = GetComponent<Light>();
        }

        private void Update()
        {
            if (_light == null) return;

            _timer += Time.deltaTime;
            float t = (Mathf.Sin(_timer * _pulseSpeed) + 1f) * 0.5f; // 0~1
            _light.intensity = Mathf.Lerp(_minIntensity, _maxIntensity, t);
