using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 鼠标点地移动角色控制器：左键点击地面移动、右键拖拽旋转视角、滚轮缩放。
    /// 自动驱动 Animator 参数（Speed、IsGrounded、Hit、Die、Interact）。
    /// </summary>
    [RequireComponent(typeof(CharacterController))]
    public class ClickToMoveController : MonoBehaviour
    {
        [Header("移动")]
        [SerializeField] private float _moveSpeed = 3f;
        [SerializeField] private float _rotationSpeed = 8f;
        [SerializeField] private float _stopDistance = 0.3f;

        [Header("摄像机")]
        [SerializeField] private float _orbitSpeed = 150f;
        [SerializeField] private float _zoomSpeed = 5f;
        [SerializeField] private float _minZoomDist = 4f;
        [SerializeField] private float _maxZoomDist = 20f;

        private CharacterController _cc;
        private Animator _anim;
        private Camera _cam;
        private Vector3 _targetPos;
        private bool _hasTarget;
        private float _currentYaw;
        private float _camDistance;
        private bool _isRightDragging;
        private int _groundLayerMask;
        private float _currentSpeed;
        private bool _wasGrounded;
        private bool _isPaused;

        // 交互目标
        private Vector3 _interactionTarget;
        private float _interactionStopDist;
        private bool _hasInteractionTarget;

        private float _pitch = 35f;

        // Animator parameter IDs
        private static readonly int AnimSpeed = Animator.StringToHash("Speed");
        private static readonly int AnimGrounded = Animator.StringToHash("IsGrounded");
        private static readonly int AnimHit = Animator.StringToHash("Hit");
        private static readonly int AnimDie = Animator.StringToHash("Die");
        private static readonly int AnimInteract = Animator.StringToHash("Interact");

        public bool IsMoving => _currentSpeed > 0.1f;

        private void Awake()
        {
            _cc = GetComponent<CharacterController>();
            _anim = GetComponent<Animator>();
            _cam = GetComponentInChildren<Camera>();
            _targetPos = transform.position;
            _currentYaw = transform.eulerAngles.y;
            _groundLayerMask = LayerMask.GetMask("Default");

            if (_cam != null)
            {
                _cam.transform.SetParent(null);
                _pitch = Mathf.Clamp(_pitch, 10f, 80f);
                _camDistance = Mathf.Clamp(12f, _minZoomDist, _maxZoomDist);
            }
        }

        private void Update()
        {
            if (!_isPaused)
            {
                HandleClickMove();
                MoveCharacter();
            }
            else
            {
                // 暂停时仍施加重力
                _cc.Move(new Vector3(0, -9.8f, 0) * Time.deltaTime);
                _currentSpeed = 0f;
                _hasTarget = false;
            }

            // 交互目标移动
            if (_hasInteractionTarget)
            {
                MoveToInteractionTarget();
            }

            HandleOrbit();
            HandleZoom();
            UpdateAnimator();
            UpdateCamera();
        }

        #region 移动

        private void HandleClickMove()
        {
            if (Input.GetMouseButtonDown(0) && !_isRightDragging)
            {
                Ray ray = _cam.ScreenPointToRay(Input.mousePosition);

                if (Physics.Raycast(ray, out RaycastHit hit, 200f))
                {
                    // 树木由 PlayerInteractor 处理，这里跳过
                    if (hit.collider.CompareTag("Tree"))
                        return;

                    if (hit.collider.CompareTag("Interactable"))
                        return;

                    if (((1 << hit.collider.gameObject.layer) & _groundLayerMask) != 0)
                    {
                        _targetPos = hit.point;
                        _hasTarget = true;
                        _hasInteractionTarget = false;
                    }
                }
            }
        }

        private void MoveCharacter()
        {
            Vector3 dir = _targetPos - transform.position;
            dir.y = 0f;

            if (dir.magnitude < _stopDistance)
            {
                _hasTarget = false;
                _currentSpeed = 0f;
                _cc.Move(new Vector3(0, -9.8f, 0) * Time.deltaTime);
                return;
            }

            // 旋转朝向目标
            Quaternion targetRot = Quaternion.LookRotation(dir.normalized);
            transform.rotation = Quaternion.Slerp(transform.rotation, targetRot, _rotationSpeed * Time.deltaTime);

            // 平滑加速/减速
            _currentSpeed = Mathf.Lerp(_currentSpeed, _moveSpeed, 6f * Time.deltaTime);

            // 移动
            Vector3 motion = dir.normalized * (_currentSpeed * Time.deltaTime);
            motion.y = -9.8f * Time.deltaTime;
            _cc.Move(motion);
        }

        #endregion

        #region 交互移动

        /// <summary>设置交互目标位置和停止距离，角色会自动走向目标</summary>
        public void SetInteractionTarget(Vector3 target, float stopDistance)
        {
            _interactionTarget = target;
            _interactionStopDist = stopDistance;
            _hasInteractionTarget = true;
            _hasTarget = false;
        }

        private void MoveToInteractionTarget()
        {
            Vector3 dir = _interactionTarget - transform.position;
            dir.y = 0f;

            if (dir.magnitude < _interactionStopDist)
            {
                _hasInteractionTarget = false;
                _currentSpeed = 0f;
                return;
            }

            Quaternion targetRot = Quaternion.LookRotation(dir.normalized);
            transform.rotation = Quaternion.Slerp(transform.rotation, targetRot, _rotationSpeed * Time.deltaTime);

            _currentSpeed = Mathf.Lerp(_currentSpeed, _moveSpeed, 6f * Time.deltaTime);

            Vector3 motion = dir.normalized * (_currentSpeed * Time.deltaTime);
            motion.y = -9.8f * Time.deltaTime;
            _cc.Move(motion);
        }

        /// <summary>暂停移动（砍树等交互时调用）</summary>
        public void PauseMovement()
        {
            _isPaused = true;
            _hasTarget = false;
            _hasInteractionTarget = false;
        }

        /// <summary>恢复移动</summary>
        public void ResumeMovement()
        {
            _isPaused = false;
        }

        #endregion

        #region 动画

        private void UpdateAnimator()
        {
            if (_anim == null) return;

            _anim.SetFloat(AnimSpeed, _currentSpeed);

            bool isGrounded = _cc.isGrounded;
            if (isGrounded != _wasGrounded)
                _anim.SetBool(AnimGrounded, isGrounded);
            _wasGrounded = isGrounded;
        }

        /// <summary>播放受击动画</summary>
        public void PlayHit() => _anim?.SetTrigger(AnimHit);

        /// <summary>播放死亡动画</summary>
        public void PlayDie() => _anim?.SetTrigger(AnimDie);

        /// <summary>播放交互动画</summary>
        public void PlayInteract() => _anim?.SetTrigger(AnimInteract);

        #endregion

        #region 摄像机

        private void HandleOrbit()
        {
            if (Input.GetMouseButtonDown(1))
                _isRightDragging = true;
            if (Input.GetMouseButtonUp(1))
                _isRightDragging = false;

            if (!_isRightDragging) return;

            float mouseX = Input.GetAxis("Mouse X");
            float mouseY = Input.GetAxis("Mouse Y");

            _currentYaw += mouseX * _orbitSpeed * Time.deltaTime;
            _pitch -= mouseY * _orbitSpeed * Time.deltaTime;
            _pitch = Mathf.Clamp(_pitch, 10f, 80f);
        }

        private void HandleZoom()
        {
            float scroll = Input.GetAxis("Mouse ScrollWheel");
            if (Mathf.Abs(scroll) > 0.01f)
            {
                _camDistance -= scroll * _zoomSpeed;
                _camDistance = Mathf.Clamp(_camDistance, _minZoomDist, _maxZoomDist);
            }
        }

        private void UpdateCamera()
        {
            if (_cam == null) return;

            float pitchRad = _pitch * Mathf.Deg2Rad;
            float height = _camDistance * Mathf.Sin(pitchRad);
            float back = _camDistance * Mathf.Cos(pitchRad);

            Quaternion yawRot = Quaternion.Euler(0, _currentYaw, 0);
            Vector3 offset = yawRot * new Vector3(0, height, -back);
            Vector3 targetPos = transform.position + offset;

            _cam.transform.position = Vector3.Lerp(_cam.transform.position, targetPos, 8f * Time.deltaTime);
            _cam.transform.LookAt(transform.position + Vector3.up * 1f);
        }

        #endregion
    }
}

using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 挂在 Knight 上，处理点击树木→走过去→自动砍树的完整交互流程。
    /// 与 ClickToMoveController 协同工作：砍树时暂停普通点击移动。
    /// </summary>
    public class PlayerInteractor : MonoBehaviour
    {
        [Header("砍树参数")]
        [SerializeField] private float _chopRange = 2f;
        [SerializeField] private float _chopDamage = 10f;
        [SerializeField] private float _chopInterval = 0.8f;

        private ClickToMoveController _moveController;
        private CharacterController _cc;
        private Animator _anim;
        private Camera _cam;

        private TreeResource _targetTree;
        private bool _isChopping;
        private float _chopTimer;

        // Animator parameter IDs
        private static readonly int AnimInteract = Animator.StringToHash("Interact");
        private static readonly int AnimSpeed = Animator.StringToHash("Speed");

        public bool IsChopping => _isChopping;

        private void Awake()
        {
            _moveController = GetComponent<ClickToMoveController>();
            _cc = GetComponent<CharacterController>();
            _anim = GetComponent<Animator>();
            _cam = GetComponentInChildren<Camera>();
        }

        private void Update()
        {
            HandleTreeClick();

            if (_isChopping && _targetTree != null)
            {
                UpdateChopping();
            }
        }

        private void HandleTreeClick()
        {
            if (!Input.GetMouseButtonDown(0)) return;

            Ray ray = _cam.ScreenPointToRay(Input.mousePosition);
            if (!Physics.Raycast(ray, out RaycastHit hit, 200f)) return;

            // 通过 Tag 查找可砍伐的树
            if (!hit.collider.CompareTag("Tree")) return;
            TreeResource tree = hit.collider.GetComponentInParent<TreeResource>();
            if (tree == null || tree.IsDead) return;

            // 设置目标树，开始走向它
            _targetTree = tree;
            _isChopping = false;
            _chopTimer = 0f;

            // 让移动控制器走向树
            _moveController.SetInteractionTarget(tree.ChopPosition, _chopRange);
        }

        private void UpdateChopping()
        {
            // 目标树已被砍倒
            if (_targetTree == null || _targetTree.IsDead)
            {
                StopChopping();
                return;
            }

            // 检查距离，太远则走过去
            float dist = Vector3.Distance(transform.position, _targetTree.ChopPosition);
            if (dist > _chopRange + 0.3f)
            {
                // 还在走向树
                _moveController.SetInteractionTarget(_targetTree.ChopPosition, _chopRange);
                return;
            }

            // 面向树
            Vector3 dir = (_targetTree.ChopPosition - transform.position);
            dir.y = 0f;
            if (dir.sqrMagnitude > 0.01f)
            {
                transform.rotation = Quaternion.Slerp(
                    transform.rotation,
                    Quaternion.LookRotation(dir),
                    8f * Time.deltaTime);
            }

            // 开始/继续砍树
            if (!_isChopping)
            {
                _isChopping = true;
                _moveController.PauseMovement();
            }

            _chopTimer += Time.deltaTime;
            if (_chopTimer >= _chopInterval)
            {
                _chopTimer = 0f;
                ChopOnce();
            }
        }

        private void ChopOnce()
        {
            if (_anim != null)
                _anim.SetTrigger(AnimInteract);

            if (_targetTree != null && !_targetTree.IsDead)
            {
                bool stillAlive = _targetTree.TakeChopDamage(_chopDamage);
                if (!stillAlive)
                {
                    // 树倒了，发奖励
                    GiveReward();
                    StopChopping();
                }
            }
        }

        private void GiveReward()
        {
            // 通过 EventBus 发放金币
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.AddGold(5);
            }
        }

        private void StopChopping()
        {
            _isChopping = false;
            _targetTree = null;
            _chopTimer = 0f;
            _moveController.ResumeMovement();
        }

        /// <summary>外部取消交互（如点击地面移动时）</summary>
        public void CancelInteraction()
        {
            StopChopping();
        }
    }
}

using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 俯视策略摄像机控制（纯鼠标）：中键拖拽平移、右键拖拽旋转、滚轮缩放、边缘滚动。
    /// </summary>
    public class RTSConsoleCamera : MonoBehaviour
    {
        [Header("移动")]
        [SerializeField] private float _panSpeed = 1f;
        [SerializeField] private float _edgeScrollMargin = 20f;
        [SerializeField] private float _edgeScrollSpeed = 30f;

        [Header("旋转")]
        [SerializeField] private float _rotateSpeed = 100f;
        [SerializeField] private float _minPitch = 10f;
        [SerializeField] private float _maxPitch = 80f;

        [Header("缩放")]
        [SerializeField] private float _zoomSpeed = 60f;
        [SerializeField] private float _minHeight = 8f;
        [SerializeField] private float _maxHeight = 120f;
        [SerializeField] private float _groundOffset = 5f;

        [Header("平滑")]
        [SerializeField] private float _smoothSpeed = 8f;

        [Header("限制")]
        [SerializeField] private Vector2 _boundMin = new Vector2(-900f, -900f);
        [SerializeField] private Vector2 _boundMax = new Vector2(900f, 900f);

        private float _currentPitch;
        private float _currentYaw;
        private float _targetHeight;
        private Vector3 _pivotPoint;
        private bool _isRightDragging;
        private bool _isMiddleDragging;
        private Terrain _terrain;

        private void Start()
        {
            _terrain = Terrain.activeTerrain;

            Vector3 angles = transform.eulerAngles;
            _currentPitch = angles.x;
            _currentYaw = angles.y;

            float groundY = GetTerrainHeight(transform.position);
            Ray ray = new Ray(transform.position, transform.forward);
            Plane ground = new Plane(Vector3.up, new Vector3(0, groundY, 0));
            if (ground.Raycast(ray, out float dist))
                _pivotPoint = ray.GetPoint(dist);
            else
                _pivotPoint = transform.position + transform.forward * 50f;

            _pivotPoint.y = GetTerrainHeight(_pivotPoint);
            _targetHeight = transform.position.y - groundY;
            _targetHeight = Mathf.Clamp(_targetHeight, _minHeight, _maxHeight);
            ApplyToTransform();
        }

        private void LateUpdate()
        {
            HandleMiddleClickPan();
            HandleEdgeScroll();
            HandleRotation();
            HandleZoom();
            ClampPivot();
            ApplyToTransform();
        }

        #region 移动

        private void HandleMiddleClickPan()
        {
            if (Input.GetMouseButtonDown(2))
            {
                _isMiddleDragging = true;
            }
            if (Input.GetMouseButtonUp(2))
            {
                _isMiddleDragging = false;
            }

            if (!_isMiddleDragging) return;

            float mouseX = Input.GetAxis("Mouse X");
            float mouseY = Input.GetAxis("Mouse Y");

            // 在摄像机 yaw 方向上平移
            Quaternion yawRot = Quaternion.Euler(0, _currentYaw, 0);
            Vector3 move = yawRot * new Vector3(-mouseX, 0, -mouseY) * _panSpeed;
            _pivotPoint += move;
        }

        private void HandleEdgeScroll()
        {
            if (_isRightDragging || _isMiddleDragging) return;

            Vector3 move = Vector3.zero;
            Vector3 mouse = Input.mousePosition;

            if (mouse.x <= _edgeScrollMargin && mouse.x >= 0) move += Vector3.left;
            if (mouse.x >= Screen.width - _edgeScrollMargin && mouse.x <= Screen.width) move += Vector3.right;
            if (mouse.y <= _edgeScrollMargin && mouse.y >= 0) move += Vector3.back;
            if (mouse.y >= Screen.height - _edgeScrollMargin && mouse.y <= Screen.height) move += Vector3.forward;

            if (move.sqrMagnitude > 0.01f)
            {
                Quaternion yawRot = Quaternion.Euler(0, _currentYaw, 0);
                _pivotPoint += yawRot * move.normalized * (_edgeScrollSpeed * Time.deltaTime);
            }
        }

        #endregion

        #region 旋转

        private void HandleRotation()
        {
            if (Input.GetMouseButtonDown(1))
            {
                _isRightDragging = true;
                UpdatePivotFromView();
            }
            if (Input.GetMouseButtonUp(1)) _isRightDragging = false;

            if (!_isRightDragging) return;

            float mouseX = Input.GetAxis("Mouse X");
            float mouseY = Input.GetAxis("Mouse Y");

            _currentYaw += mouseX * _rotateSpeed * Time.deltaTime;
            _currentPitch -= mouseY * _rotateSpeed * Time.deltaTime;
            _currentPitch = Mathf.Clamp(_currentPitch, _minPitch, _maxPitch);
        }

        private void UpdatePivotFromView()
        {
            float groundY = GetTerrainHeight(transform.position);
            Ray ray = new Ray(transform.position, transform.forward);
            Plane ground = new Plane(Vector3.up, new Vector3(0, groundY, 0));
            if (ground.Raycast(ray, out float dist))
                _pivotPoint = ray.GetPoint(dist);
            _pivotPoint.y = GetTerrainHeight(_pivotPoint);
        }

        #endregion

        #region 缩放

        private void HandleZoom()
        {
            float scroll = Input.GetAxis("Mouse ScrollWheel");
            if (Mathf.Abs(scroll) > 0.001f)
            {
                _targetHeight -= scroll * _zoomSpeed;
                _targetHeight = Mathf.Clamp(_targetHeight, _minHeight, _maxHeight);
            }
        }

        #endregion

        private void ClampPivot()
        {
            _pivotPoint.x = Mathf.Clamp(_pivotPoint.x, _boundMin.x, _boundMax.x);
            _pivotPoint.z = Mathf.Clamp(_pivotPoint.z, _boundMin.y, _boundMax.y);
            _pivotPoint.y = GetTerrainHeight(_pivotPoint);
        }

        private void ApplyToTransform()
        {
            float pitchRad = _currentPitch * Mathf.Deg2Rad;
            float distance = _targetHeight / Mathf.Max(Mathf.Sin(pitchRad), 0.1f);

            Quaternion rot = Quaternion.Euler(_currentPitch, _currentYaw, 0f);
            Vector3 offset = rot * Vector3.back * distance;
            Vector3 targetPos = _pivotPoint + offset;

            float groundY = GetTerrainHeight(targetPos);
            targetPos.y = Mathf.Max(targetPos.y, groundY + _groundOffset);

            transform.position = Vector3.Lerp(transform.position, targetPos, _smoothSpeed * Time.deltaTime);
            transform.rotation = Quaternion.Slerp(transform.rotation, rot, _smoothSpeed * Time.deltaTime);
        }

        private float GetTerrainHeight(Vector3 worldPos)
        {
            if (_terrain != null)
            {
                Vector3 terrainLocal = worldPos - _terrain.transform.position;
                Vector3 normalized = new Vector3(
                    terrainLocal.x / _terrain.terrainData.size.x,
                    0f,
                    terrainLocal.z / _terrain.terrainData.size.z);

                if (normalized.x >= 0f && normalized.x <= 1f && normalized.z >= 0f && normalized.z <= 1f)
                    return _terrain.SampleHeight(worldPos) + _terrain.transform.position.y;
            }
            return 0f;
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Shared.Player
{
    /// <summary>
    /// 统一玩家档案，管理跨所有模块共享的玩家数据。
    /// 包含货币（金币、钻石）、等级、经验值。
    /// </summary>
    public class PlayerProfile : Singleton<PlayerProfile>
    {
        [Header("初始值")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _gold;
        private int _diamond;
        private int _stamina;
        private int _level = 1;
        private int _currentExp;

        #region 属性

        public int Gold => _gold;
        public int Diamond => _diamond;
        public int Stamina => _stamina;
        public int Level => _level;
        public int CurrentExp => _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => GetExpRequiredForLevel(_level);
        public float ExpProgress => _level >= _maxLevel ? 1f : (float)_currentExp / ExpToNextLevel;
        public bool IsMaxLevel => _level >= _maxLevel;

        #endregion

        #region 事件

        public event Action<int> OnGoldChanged;
        public event Action<int> OnDiamondChanged;
        public event Action<int> OnStaminaChanged;
        public event Action<int> OnLevelChanged;
        public event Action<int, int> OnExpChanged;

        #endregion

        protected override void Awake()
        {
            base.Awake();
            _gold = _initialGold;
            _diamond = _initialDiamond;
            _stamina = _initialStamina;
        }

        private void Start()
        {
            LoadFromSave();
        }

        #region 金币

        public bool HasEnoughGold(int amount) => _gold >= amount;

        public void AddGold(int amount, string source = "")
        {
            if (amount <= 0) return;
            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = amount,
                DiamondDelta = 0
            });
        }

        public bool SpendGold(int amount, string source = "")
        {
            if (!HasEnoughGold(amount)) return false;
            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = -amount,
                DiamondDelta = 0
            });
            return true;
        }

        #endregion

        #region 钻石

        public bool HasEnoughDiamond(int amount) => _diamond >= amount;

        public void AddDiamond(int amount, string source = "")
        {
            if (amount <= 0) return;
            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = amount
            });
        }

        public bool SpendDiamond(int amount, string source = "")
        {
            if (!HasEnoughDiamond(amount)) return false;
            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = -amount
            });
            return true;
        }

        #endregion

        #region 体力

        public bool HasEnoughStamina(int amount) => _stamina >= amount;

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;
            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
        }

        public bool SpendStamina(int amount)
        {
            if (!HasEnoughStamina(amount)) return false;
            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            return true;
        }

        #endregion

        #region 等级与经验

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            GlobalEventBus.Publish(new PlayerLevelChangedEvent
            {
                OldLevel = oldLevel,
                NewLevel = _level,
                CurrentExp = _currentExp,
                ExpToNext = ExpToNextLevel
            });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                Debug.Log($"[PlayerProfile] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            var data = saveSystem.CurrentSave.player;
            _gold = data.gold > 0 ? data.gold : _initialGold;
            _diamond = data.diamond > 0 ? data.diamond : _initialDiamond;
            _stamina = data.stamina > 0 ? data.stamina : _initialStamina;
            _level = Mathf.Clamp(data.playerLevel, 1, _maxLevel);
            _currentExp = Mathf.Clamp(data.playerExp, 0, ExpToNextLevel);

            Debug.Log($"[PlayerProfile] 从存档加载: Lv.{_level}, Gold={_gold}, Diamond={_diamond}");
        }

        public void PersistToSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            saveSystem.CurrentSave.player.gold = _gold;
            saveSystem.CurrentSave.player.diamond = _diamond;
            saveSystem.CurrentSave.player.stamina = _stamina;
            saveSystem.CurrentSave.player.playerLevel = _level;
            saveSystem.CurrentSave.player.playerExp = _currentExp;
            saveSystem.SaveGame();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑存档数据。
    /// </summary>
    [Serializable]
    public class BuildingSaveEntry
    {
        public string buildingId;
        public float posX;
        public float posY;   // 旧 2D 兼容
        public float posZ;   // 3D Z 坐标
        public int rotation;  // 0/90/180/270
        public int level;
    }

    /// <summary>
    /// 家园存档数据。
    /// </summary>
    [Serializable]
    public class HomeSaveData
    {
        public int wood;
        public int stone;
        public int food;
        public List<BuildingSaveEntry> buildings = new List<BuildingSaveEntry>();
    }

    /// <summary>
    /// 建筑管理器，负责建筑的放置、升级和拆除。
    /// </summary>
    public class BuildingManager : MonoBehaviour
    {
        [Header("建筑配置列表")]
        [SerializeField] private BuildingData[] _availableBuildings;
        [SerializeField] private GridManager _gridManager;

        private List<BuildingBase> _buildings = new List<BuildingBase>();

        public BuildingData[] AvailableBuildings => _availableBuildings;
        public IReadOnlyList<BuildingBase> Buildings => _buildings;
        public GridManager Grid => _gridManager;

        #region 放置与检测

        /// <summary>
        /// 在指定世界坐标放置建筑（2.5D：XZ 平面）。
        /// </summary>
        public BuildingBase PlaceBuilding(BuildingData data, Vector3 worldPos)
        {
            // 扣除建造费用
            var levelData = data.GetLevelData(1);
            var profile = PlayerProfile.Instance;
            if (profile != null && levelData.buildCost > 0 && !profile.HasEnoughGold(levelData.buildCost))
            {
                Debug.LogWarning("[BuildingManager] 金币不足");
                return null;
            }
            profile?.SpendGold(levelData.buildCost, "building_place");

            // 实例化建筑
            GameObject go = data.prefab != null
                ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                : CreatePlaceholderBuilding(data, worldPos);

            BuildingBase building = go.GetComponent<BuildingBase>();
            if (building == null)
                building = go.AddComponent<BuildingBase>();

            building.Initialize(data);
            _buildings.Add(building);

            // 占用网格
            if (_gridManager != null)
            {
                Vector2Int gridPos = _gridManager.WorldToGrid(worldPos);
                _gridManager.OccupyArea(gridPos, data.gridSize, building);
                building.SetGridInfo(gridPos, 0);
            }

            Debug.Log($"[BuildingManager] 建筑已放置: {data.buildingName} at {worldPos}");
            return building;
        }

        /// <summary>
        /// 拆除指定建筑，释放网格占用。
        /// </summary>
        public bool RemoveBuilding(BuildingBase building)
        {
            if (building == null || !_buildings.Contains(building))
                return false;

            // 释放网格占用
            if (_gridManager != null)
                _gridManager.ReleaseBuilding(building);

            _buildings.Remove(building);
            building.Demolish();
            return true;
        }

        /// <summary>
        /// 获取指定位置附近的建筑。
        /// </summary>
        public BuildingBase GetBuildingNear(Vector3 worldPos, float radius = 1f)
        {
            float minDist = float.MaxValue;
            BuildingBase nearest = null;
            foreach (var b in _buildings)
            {
                if (b == null) continue;
                float dist = Vector3.Distance(b.transform.position, worldPos);
                if (dist < radius && dist < minDist)
                {
                    minDist = dist;
                    nearest = b;
                }
            }
            return nearest;
        }

        #endregion

        #region 存档

        /// <summary>
        /// 导出所有建筑的存档数据。
        /// </summary>
        public List<BuildingSaveEntry> ExportSaveData()
        {
            var result = new List<BuildingSaveEntry>();
            foreach (var building in _buildings)
            {
                if (building == null) continue;
                result.Add(new BuildingSaveEntry
                {
                    buildingId = building.Data.buildingId,
                    posX = building.transform.position.x,
                    posY = 0f,
                    posZ = building.transform.position.z,
                    rotation = building.Rotation,
                    level = building.CurrentLevel
                });
            }
            return result;
        }

        /// <summary>
        /// 从存档数据恢复所有建筑。
        /// </summary>
        public void RestoreFromSaveData(List<BuildingSaveEntry> entries)
        {
            if (entries == null) return;

            foreach (var entry in entries)
            {
                BuildingData data = FindBuildingData(entry.buildingId);
                if (data == null)
                {
                    Debug.LogWarning($"[BuildingManager] 未找到建筑配置: {entry.buildingId}");
                    continue;
                }

                // 兼容旧 2D 存档：如果 posZ 为 0 且 posY 不为 0，用 posY 作为 Z
                float z = entry.posZ;
                if (z == 0f && entry.posY != 0f)
                    z = entry.posY;

                Vector3 worldPos = new Vector3(entry.posX, 0f, z);
                GameObject go = data.prefab != null
                    ? Instantiate(data.prefab, worldPos, Quaternion.Euler(0f, entry.rotation, 0f), transform)
                    : CreatePlaceholderBuilding(data, worldPos);

                BuildingBase building = go.GetComponent<BuildingBase>();
                if (building == null)
                    building = go.AddComponent<BuildingBase>();

                building.RestoreFromSave(data, entry.level);
                building.SetGridInfo(
                    _gridManager != null ? _gridManager.WorldToGrid(worldPos) : Vector2Int.zero,
                    entry.rotation
                );

                // 恢复旋转
                building.transform.rotation = Quaternion.Euler(0f, entry.rotation, 0f);

                // 占用网格
                if (_gridManager != null)
                {
                    Vector2Int gridPos = _gridManager.WorldToGrid(worldPos);
                    _gridManager.OccupyArea(gridPos, data.gridSize, building);
                }

                _buildings.Add(building);
            }

            Debug.Log($"[BuildingManager] 从存档恢复 {entries.Count} 个建筑");
        }

        #endregion

        #region 辅助

        private BuildingData FindBuildingData(string buildingId)
        {
            if (_availableBuildings == null) return null;
            foreach (var data in _availableBuildings)
            {
                if (data.buildingId == buildingId)
                    return data;
            }
            return null;
        }

        private GameObject CreatePlaceholderBuilding(BuildingData data, Vector3 worldPos)
        {
            GameObject go = GameObject.CreatePrimitive(PrimitiveType.Cube);
            go.name = $"Building_{data.buildingName}";
            go.transform.position = worldPos + new Vector3(0f, 0.25f, 0f);
            go.transform.SetParent(transform);
            go.transform.localScale = new Vector3(data.gridSize.x, 0.5f, data.gridSize.y);

            var renderer = go.GetComponent<Renderer>();
            var mat = new Material(Shader.Find("Universal Render Pipeline/Lit"));
            mat.color = GetBuildingColor(data.buildingType);
            renderer.sharedMaterial = mat;

            // 移除碰撞器（建筑不需要物理）
            var collider = go.GetComponent<Collider>();
            if (collider != null) DestroyImmediate(collider);

            return go;
        }

        private Color GetBuildingColor(BuildingType type)
        {
            switch (type)
            {
                case BuildingType.ResourceGen: return new Color(0.2f, 0.8f, 0.3f);
                case BuildingType.Portal: return new Color(0.3f, 0.5f, 1f);
                case BuildingType.Storage: return new Color(0.9f, 0.7f, 0.2f);
                case BuildingType.Decoration: return new Color(0.9f, 0.4f, 0.7f);
                case BuildingType.Special: return new Color(1f, 0.5f, 0.1f);
                default: return Color.white;
            }
        }

        #endregion
    }
}

using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑基类，所有建筑类型继承此类。
    /// 管理建筑的等级、升级和拆除。
    /// </summary>
    public class BuildingBase : MonoBehaviour
    {
        [Header("建筑配置")]
        [SerializeField] protected BuildingData _data;

        protected int _currentLevel = 1;
        protected bool _isPlaced = false;
        protected float _productionTimer;
        protected Vector2Int _gridPos;
        protected int _rotation;

        #region 属性

        public BuildingData Data => _data;
        public int CurrentLevel => _currentLevel;
        public bool IsPlaced => _isPlaced;
        public bool IsMaxLevel => _currentLevel >= _data.MaxLevel;
        public BuildingLevel CurrentLevelData => _data.GetLevelData(_currentLevel);
        public Vector2Int GridPos => _gridPos;
        public int Rotation => _rotation;

        #endregion

        #region 初始化

        /// <summary>
        /// 初始化建筑。
        /// </summary>
        public virtual void Initialize(BuildingData data)
        {
            _data = data;
            _currentLevel = 1;
            _isPlaced = true;
            _productionTimer = 0f;
        }

        /// <summary>
        /// 从存档恢复建筑状态。
        /// </summary>
        public virtual void RestoreFromSave(BuildingData data, int level)
        {
            _data = data;
            _currentLevel = Mathf.Clamp(level, 1, data.MaxLevel);
            _isPlaced = true;
            _productionTimer = 0f;
        }

        /// <summary>
        /// 设置建筑的网格位置和旋转。
        /// </summary>
        public void SetGridInfo(Vector2Int gridPos, int rotation)
        {
            _gridPos = gridPos;
            _rotation = rotation;
        }

        #endregion

        #region 升级与拆除

        /// <summary>
        /// 升级建筑。
        /// </summary>
        public virtual bool Upgrade()
        {
            if (IsMaxLevel)
            {
                Debug.LogWarning($"[BuildingBase] 建筑已满级: {_data.buildingName}");
                return false;
            }

            var levelData = _data.GetLevelData(_currentLevel + 1);
            var profile = PlayerProfile.Instance;
            if (profile == null || !profile.HasEnoughGold(levelData.upgradeCost))
            {
                Debug.LogWarning($"[BuildingBase] 金币不足，无法升级: {_data.buildingName}");
                return false;
            }

            profile.SpendGold(levelData.upgradeCost, "building_upgrade");
            _currentLevel++;
            OnUpgraded();
            Debug.Log($"[BuildingBase] 建筑升级: {_data.buildingName} Lv.{_currentLevel}");
            return true;
        }

        /// <summary>
        /// 拆除建筑，返还部分资源。
        /// </summary>
        public virtual int Demolish()
        {
            int refund = GetSellValue();
            var profile = PlayerProfile.Instance;
            profile?.AddGold(refund, "building_demolish");
            _isPlaced = false;
            Debug.Log($"[BuildingBase] 建筑拆除: {_data.buildingName}, 返还 {refund} 金币");
            Destroy(gameObject);
            return refund;
        }

        /// <summary>
        /// 获取出售价值（建造费用的 60%）。
        /// </summary>
        public int GetSellValue()
        {
            int totalCost = 0;
            for (int i = 1; i <= _currentLevel; i++)
            {
                var ld = _data.GetLevelData(i);
                totalCost += i == 1 ? ld.buildCost : ld.upgradeCost;
            }
            return Mathf.RoundToInt(totalCost * 0.6f);
        }

        #endregion

        #region 子类重写

        /// <summary>升级后的回调。</summary>
        protected virtual void OnUpgraded() { }

        /// <summary>每帧更新（用于资源产出等）。</summary>
        protected virtual void BuildingUpdate() { }

        #endregion

        private void Update()
        {
            // 场景中预放置的建筑：如果已有 _data 但 _isPlaced 为 false，自动标记
            if (!_isPlaced && _data != null)
            {
                _isPlaced = true;
            }

            if (!_isPlaced) return;
            BuildingUpdate();
        }
    }
}

